args.sparql:
SELECT ?player ?playerLabel ?yardsValue
WHERE {
  ?game wdt:P1556 wd:Q1215884 .
  ?game wdt:P580 ?player .
  ?player wdt:P2892 ?yards .
  ?yards wikibase:quantityValue ?yardsValue .
  OPTIONAL { ?player rdfs:label ?playerLabel . FILTER (LANG(?playerLabel) = 'en') }
}
ORDER BY DESC(?yardsValue)
LIMIT 1

